#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<vector<int>> isConnected(n, vector<int>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> isConnected[i][j];
        }
    }
    vector<bool> visited(n, false);
    int province_count = 0;
    function<void(int)> dfs = [&](int city) {
        visited[city] = true;
        for (int neighbor = 0; neighbor < n; neighbor++) {
            if (isConnected[city][neighbor] == 1 && !visited[neighbor]) {
                dfs(neighbor);
            }
        }
    };
    for (int city = 0; city < n; city++) {
        if (!visited[city]) {
            dfs(city);
            province_count++;
        }
    }
    cout << province_count;
}
